import{_ as e,a,b as n,c as o,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Thêm Telegram Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/telegram.md","filePath":"vi-VN/upload/telegram.md","lastUpdated":1781962217000}'),c={name:"vi-VN/upload/telegram.md"};function s(m,t,g,p,b,u){return d(),i("div",null,[...t[0]||(t[0]=[h('<h1 id="them-telegram-channel" tabindex="-1">Thêm Telegram Channel <a class="header-anchor" href="#them-telegram-channel" aria-label="Permalink to &quot;Thêm Telegram Channel&quot;">​</a></h1><h2 id="can-chuan-bi-gi-truoc-khi-bat-đau" tabindex="-1">Cần chuẩn bị gì trước khi bắt đầu <a class="header-anchor" href="#can-chuan-bi-gi-truoc-khi-bat-đau" aria-label="Permalink to &quot;Cần chuẩn bị gì trước khi bắt đầu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Telegram account</td><td>Dùng để tạo bot và storage channel.</td></tr><tr><td><code>@BotFather</code></td><td>Dùng để tạo Telegram bot.</td></tr><tr><td>Một Telegram channel</td><td>Nơi lưu trữ file cuối cùng.</td></tr><tr><td><code>@userinfobot</code></td><td>Dùng để tra <code>Chat ID</code> của channel.</td></tr></tbody></table><h2 id="them-o-đau" tabindex="-1">Thêm ở đâu <a class="header-anchor" href="#them-o-đau" aria-label="Permalink to &quot;Thêm ở đâu&quot;">​</a></h2><ol><li>Mở System Settings.</li><li>Vào Upload Settings.</li><li>Nhấn Add Channel ở góc trên bên phải.</li><li>Chọn <code>Telegram</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Tác dụng</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết cho channel này, ví dụ &quot;Telegram Primary&quot;.</td><td>Required</td></tr><tr><td>Active</td><td>Bật hoặc tắt channel này.</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Token của Telegram bot.</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>ID của Telegram channel.</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Chỉ dùng nếu truy cập Telegram không ổn định. Nhập proxy URL đầy đủ, bao gồm <code>https://</code>.</td><td>Optional</td></tr><tr><td>Remark</td><td>Ghi chú để bảo trì sau này.</td><td>Optional</td></tr></tbody></table><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><h3 id="_1-tao-telegram-bot" tabindex="-1">1. Tạo Telegram Bot <a class="header-anchor" href="#_1-tao-telegram-bot" aria-label="Permalink to &quot;1. Tạo Telegram Bot&quot;">​</a></h3><ol><li>Mở Telegram và tìm <code>@BotFather</code>.</li><li>Mở chat rồi nhấn <code>Start</code>.</li><li>Gửi <code>/newbot</code>.</li><li>Làm theo prompt để nhập tên hiển thị của bot.</li><li>Làm theo prompt để nhập bot username. Username thường cần kết thúc bằng <code>bot</code>.</li><li>Sau khi bot được tạo, <code>@BotFather</code> sẽ trả về bot token.</li></ol><p>Token này chính là <code>Bot Token</code> cần nhập trong ImgBed.</p><p><img src="'+e+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-tao-channel" tabindex="-1">2. Tạo Channel <a class="header-anchor" href="#_2-tao-channel" aria-label="Permalink to &quot;2. Tạo Channel&quot;">​</a></h3><ol><li>Trong Telegram, nhấn New Channel.</li><li>Nhập channel name.</li><li>Hoàn tất tạo channel.</li></ol><p>Có thể dùng cả public channel và private channel.</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-them-bot-vao-channel" tabindex="-1">3. Thêm Bot vào Channel <a class="header-anchor" href="#_3-them-bot-vao-channel" aria-label="Permalink to &quot;3. Thêm Bot vào Channel&quot;">​</a></h3><ol><li>Mở channel vừa tạo.</li><li>Mở channel settings.</li><li>Thêm member hoặc administrator.</li><li>Tìm bot username bạn đã tạo.</li><li>Thêm bot vào channel.</li></ol><p>Để upload ổn định nhất, nên cấp quyền administrator cho bot.</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-lay-channel-id-bang-user-info-get-id-idbot" tabindex="-1">4. Lấy Channel ID bằng User Info - Get ID - IDbot <a class="header-anchor" href="#_4-lay-channel-id-bang-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Lấy Channel ID bằng User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Tìm <code>@userinfobot</code> trong Telegram. Tên hiển thị thường là <code>User Info - Get ID - IDbot</code>.</li><li>Mở chat và nhấn <code>Start</code>.</li><li>Chọn <code>Channel</code> trong các lựa chọn bot đưa ra.</li><li>Trong message picker, chọn target channel rồi gửi tới <code>@userinfobot</code>.</li><li>Khi <code>@userinfobot</code> trả kết quả, copy số hiển thị dạng <code>Id: -100...</code>.</li></ol><p>Số bắt đầu bằng <code>-100</code> là <code>Session ID (Chat ID)</code> mà ImgBed cần.</p><p><img src="'+o+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-đien-telegram-channel-trong-imgbed" tabindex="-1">5. Điền Telegram Channel trong ImgBed <a class="header-anchor" href="#_5-đien-telegram-channel-trong-imgbed" aria-label="Permalink to &quot;5. Điền Telegram Channel trong ImgBed&quot;">​</a></h3><p>Quay lại channel configuration dialog và điền như sau:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Tên channel tùy chọn, ví dụ <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Recommended.</td></tr><tr><td>Bot Token</td><td>Bot token từ <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Số <code>-100...</code> do <code>@userinfobot</code> trả về.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Chỉ nhập khi cần, ví dụ <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>Ghi chú tùy chọn.</td></tr></tbody></table><p>Điền xong thì nhấn Save.</p><p><img src="'+l+`" alt="Edit the configuration" loading="lazy"></p><h2 id="cach-kiem-tra" tabindex="-1">Cách kiểm tra <a class="header-anchor" href="#cach-kiem-tra" aria-label="Permalink to &quot;Cách kiểm tra&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cách kiểm tra</th></tr></thead><tbody><tr><td>Channel card xuất hiện</td><td>Sau khi save, trang Upload Settings cần hiển thị Telegram channel card.</td></tr><tr><td>Channel bật được</td><td>Active switch nên giữ ở trạng thái on.</td></tr><tr><td>Configuration đã lưu</td><td>Detail view cần cho thấy Bot Token và Chat ID đã được lưu.</td></tr><tr><td>Upload hoạt động</td><td>Upload một test image và xác nhận file xuất hiện trong Telegram channel đích.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tạo bot bằng @BotFather</span></span>
<span class="line"><span>-&gt; Lưu Bot Token</span></span>
<span class="line"><span>-&gt; Tạo Telegram channel</span></span>
<span class="line"><span>-&gt; Thêm bot vào channel và cấp quyền administrator</span></span>
<span class="line"><span>-&gt; Tìm @userinfobot và chọn Channel</span></span>
<span class="line"><span>-&gt; Forward bất kỳ message nào từ channel tới @userinfobot</span></span>
<span class="line"><span>-&gt; Copy Id: -100... được trả về</span></span>
<span class="line"><span>-&gt; Nhập Bot Token và Chat ID trong ImgBed</span></span>
<span class="line"><span>-&gt; Save và upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const C=r(c,[["render",s]]);export{f as __pageData,C as default};
